import { Anthropic } from '@anthropic-ai/sdk';
import { addAiModule, saveAiModulePromptAndTranscript } from './ai-modules';

const SYSTEM_PROMPT = `
You are a DSP expert specializing in TypeScript. You generate modules for a specific synthesizer
framework.

At the heart of this framework is a class called Signal that represents a value that changes over
time.To create a Signal, you call Signal.new(config), where the type of config is:

type Config = {
  nextSample: () => number;
  noteOn?: () => void;
  noteOff?: () => void;
};

A signal's value is computed by nextSample(). If you need to know when a note is played or stopped
(e.g., for an envelope generator), you can provide callbacks for noteOn and noteOff.

To access the current value of a Signal, you call.value on it. The system ensures that nextSample()
is not called more than once per frame.

There is also a helper function scalar(value: number) that creates a Signal whose value is always
the given number. This is useful for defining default parameter values.

A Module is created with Module.make(), which takes three arguments:

1. defaultParamValues: an object mapping parameter names to factory functions that return the
   default Signal for each parameter. For example: { freq: () => scalar(440) }
2. makeSignal: a function that receives the actual parameters (Signals) as an object and returns a
   Signal for the module's output. Any state and helper functions the Signal needs should be
   declared in the closure of makeSignal.
3. description: an optional string describing the module and its parameters. Please include helpful
   information about the module, like its purpose and how to get the best sound out of it.

When I ask you to create a module, you will generate the module's code, then use the add_module
tool to add it to the synthesizer. Only do this once you have fully designed and written the
module's code. Do not call it until the code is finished!

Here's an example of the code you might generate if I ask you to create a sine wave oscillator:

Module.make(
  { input: () => scalar(440) },
  (params) => {
    const f = params.input;
    let phase = 0;
    return Signal.new({
      nextSample: () => {
        const sample = Math.sin(phase * TAU);
        const phaseInc = f.value * SAMPLE_RATE_RECIP;
        phase += phaseInc;
        phase -= Math.floor(phase);
        return sample;
      },
    });
  },
  'A sine wave oscillator. Input is in Hz. Output is in the range -1 to 1.'
)

Note that nextSample() is called at audio rate, so avoid any allocations inside it to prevent GC
pauses during playback.

The following constants are available globally(do not redeclare them):

const TAU = Math.PI * 2;
const SAMPLE_RATE = 48000;
const SAMPLE_RATE_RECIP = 1 / SAMPLE_RATE;

The values of frequency parameters should be in Hertz.
Audio signals are always in the range -1 to 1.
All other parameters (e.g., balance, depth, drive, etc.) should be in the range 0 to 1.

The module and parameter names should be camelCase and should never use underscores. Make sure you
don't have any compiler errors, like uses of undeclared variables!
`;

let _anthropic: Anthropic | null = null;
function anthropic() {
  if (!_anthropic) {
    _anthropic = new Anthropic({
      apiKey: getApiKeys().anthropic,
      dangerouslyAllowBrowser: true,
    });
  }
  return _anthropic;
}

function showStreamingOverlay() {
  const overlay = document.createElement('div');
  overlay.className = 'ai-stream-overlay';
  overlay.style.cssText = `
    position: fixed;
    inset: 0;
    z-index: 10000;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(0, 0, 0, 0.05);
    backdrop-filter: blur(3px);
    -webkit-backdrop-filter: blur(3px);
  `;
  const panel = document.createElement('div');
  panel.style.cssText = `
    width: 80%;
    height: 80%;
    max-width: 80vw;
    max-height: 80vh;
    border-radius: 8px;
    background: #fff;
    box-shadow: 0 20px 60px rgba(0,0,0,0.2);
    display: flex;
    flex-direction: column;
    overflow: hidden;
  `;
  const content = document.createElement('div');
  content.style.cssText = `
    flex: 1;
    display: flex;
    flex-direction: column;
    min-height: 0;
  `;
  const textarea = document.createElement('textarea');
  textarea.readOnly = true;
  textarea.style.cssText = `
    flex: 1;
    width: 100%;
    min-height: 0;
    margin: 0;
    padding: 16px;
    border: none;
    resize: none;
    font-family: ui-monospace, monospace;
    font-size: 14px;
    line-height: 1.5;
    color: #1a1a1a;
  `;
  let autoScroll = true;
  textarea.addEventListener('scroll', () => {
    const bottomThreshold = 4;
    const distanceFromBottom = textarea.scrollHeight - (textarea.scrollTop + textarea.clientHeight);
    autoScroll = distanceFromBottom <= bottomThreshold;
  });
  const footer = document.createElement('div');
  footer.style.cssText = `
    padding: 8px 12px;
    border-top: 1px solid #e5e5e5;
    display: flex;
    justify-content: flex-end;
    gap: 8px;
    background: #fafafa;
  `;
  const actionButton = document.createElement('button');
  actionButton.type = 'button';
  actionButton.textContent = 'Close';
  actionButton.style.cssText = `
    padding: 4px 10px;
    border-radius: 4px;
    border: 1px solid #d0d0d0;
    background: #f5f5f5;
    color: #333;
    font-size: 13px;
    cursor: pointer;
  `;
  actionButton.onmouseenter = () => {
    actionButton.style.background = '#ededed';
  };
  actionButton.onmouseleave = () => {
    actionButton.style.background = '#f5f5f5';
  };
  footer.appendChild(actionButton);
  content.appendChild(textarea);
  content.appendChild(footer);
  panel.appendChild(content);
  overlay.appendChild(panel);
  document.body.appendChild(overlay);
  return {
    appendText(text: string) {
      textarea.value += text;
      if (autoScroll) {
        textarea.scrollTop = textarea.scrollHeight;
      }
    },
    getText() {
      return textarea.value;
    },
    setButton(label: string, onClick: () => void) {
      actionButton.textContent = label;
      actionButton.onclick = onClick;
    },
    remove() {
      overlay.remove();
    },
  };
}

const tools: Anthropic.Tool[] = [
  {
    name: 'add_module',
    description:
      'Add a new module to the synthesizer. Call this ONCE when the module code is complete.',
    input_schema: {
      type: 'object' as const,
      properties: {
        name: {
          type: 'string',
          description: 'The name of the new module, in camelCase',
        },
        code: { type: 'string', description: 'The code for the new module' },
      },
      required: ['name', 'code'],
    },
  },
];

export async function generateModule(prompt: string) {
  const overlay = showStreamingOverlay();
  return await _generateModule(prompt, overlay);
}

async function _generateModule(prompt: string, overlay: ReturnType<typeof showStreamingOverlay>) {
  let name: string | null = null;
  let cancelled = false;

  if (overlay.setButton) {
    overlay.setButton('Cancel', () => {
      cancelled = true;
      overlay.remove();
    });
  }

  const messages: Anthropic.MessageParam[] = [{ role: 'user', content: prompt }];
  while (true) {
    if (cancelled) {
      break;
    }
    const stream = anthropic().messages.stream({
      // model: 'claude-opus-4-6',
      // model: 'claude-sonnet-4-6',
      model: 'claude-haiku-4-5',
      max_tokens: 20480,
      thinking: {
        type: 'enabled',
        budget_tokens: 10000,
      },
      system: SYSTEM_PROMPT,
      stream: true,
      tools,
      messages,
    });

    if (overlay.setButton) {
      overlay.setButton('Cancel', () => {
        cancelled = true;
        try {
          stream.abort();
        } catch {
          // ignore abort errors
        }
        overlay.remove();
      });
    }

    try {
      for await (const event of stream) {
        if (cancelled) {
          try {
            stream.abort();
          } catch {
            // ignore abort errors
          }
          break;
        }
        if (event.type === 'content_block_start') {
          switch (event.content_block.type) {
            case 'thinking':
              overlay.appendText('\n\n[thinking]\n');
              break;
            case 'text':
              overlay.appendText('\n\n[talking]\n');
              break;
            case 'tool_use':
              overlay.appendText(`\n\n[tool use: ${event.content_block.name}]\n`);
              break;
          }
        } else if (event.type === 'content_block_delta') {
          switch (event.delta.type) {
            case 'thinking_delta':
              overlay.appendText(event.delta.thinking);
              break;
            case 'text_delta':
              overlay.appendText(event.delta.text);
              break;
            case 'input_json_delta':
              overlay.appendText(event.delta.partial_json);
              break;
          }
        }
      }
    } catch (e) {
      if (cancelled) {
        break;
      }
      throw e;
    }

    if (cancelled) {
      break;
    }

    const toolCalls: Anthropic.ToolUseBlock[] = [];
    const finalMessage = await stream.finalMessage();
    for (const block of finalMessage.content) {
      if (block.type === 'tool_use') {
        toolCalls.push(block);
      }
    }

    if (toolCalls.length === 0) {
      break;
    }

    messages.push({
      role: 'assistant',
      content: [
        { type: 'text', text: overlay.getText() + '\n\n[executing tool...]' },
        ...toolCalls,
      ],
    });

    const toolResults: Anthropic.ToolResultBlockParam[] = [];
    for (const tool of toolCalls) {
      if (tool.name === 'add_module') {
        const input = tool.input as { name: string; code: string };
        console.log('>>> add_module', input);
        try {
          name = addAiModule(input.name, input.code);
          toolResults.push({
            type: 'tool_result',
            tool_use_id: tool.id,
            content: 'Success: module installed!',
          });
        } catch (e: any) {
          console.error('error installing ai-generated module', name, e);
          toolResults.push({
            type: 'tool_result',
            tool_use_id: tool.id,
            content: `Error: ${e.message}\n\nPlease fix the code and try again.`,
            is_error: true,
          });
        }
      }
    }

    messages.push({ role: 'user', content: toolResults });
  }
  if (!cancelled && name) {
    saveAiModulePromptAndTranscript(name, prompt, overlay.getText());
  }
  if (!cancelled && overlay.setButton) {
    overlay.setButton('Close', () => {
      overlay.remove();
    });
  }
  return cancelled ? null : name;
}

function getApiKeys(): { anthropic: string; google: string } {
  let apiKeys = localStorage.getItem('api-keys');
  if (!apiKeys || apiKeys === 'null') {
    const apiKeys = prompt('enter api keys', `{ "anthropic": "", "google": "" }`);
    localStorage.setItem('api-keys', apiKeys);
  }
  return JSON.parse(apiKeys);
}
